# -*- coding: utf-8 -*-
"""jummal_sourates.py - jummal (valeur abjad) de chaque sourate, une par une.

Valeurs = TABLE JUMMAL VALIDEE de MASTER_JUMMAL (regle mashriqi corrigee ;
SigmaJ total du corpus = 23 476 120). Table embarquee : AUCUN autre fichier requis.

    python3 jummal_sourates.py                    -> tableau + ecrit jummal_par_sourate.csv
    python3 jummal_sourates.py table_externe.csv  -> depuis une table par verset externe
                                                     (colonnes : sourate,verset,jummal[,lettres])
"""
import sys, csv, io, gzip, base64

def charger_table(chemin=None):
    if chemin:
        return open(chemin, encoding="utf-8-sig").read()
    return gzip.decompress(base64.b64decode(_TABLE_GZ)).decode("utf-8")

def par_sourate(csv_text):
    agg = {}  # sourate -> [jummal, versets, lettres]
    for r in csv.DictReader(io.StringIO(csv_text)):
        s = int(r["sourate"])
        a = agg.setdefault(s, [0, 0, 0])
        a[0] += int(r["jummal"]); a[1] += 1; a[2] += int(r.get("lettres", 0) or 0)
    return agg

def main():
    chemin = sys.argv[1] if len(sys.argv) > 1 else None
    agg = par_sourate(charger_table(chemin))
    print(f"{"sourate":>7} {"versets":>8} {"lettres":>9} {"jummal":>13}")
    print("-" * 41)
    tj = tv = tl = 0
    for s in sorted(agg):
        j, v, l = agg[s]; tj += j; tv += v; tl += l
        print(f"{s:>7} {v:>8} {l:>9} {j:>13,}")
    print("-" * 41)
    print(f"{"TOTAL":>7} {tv:>8} {tl:>9} {tj:>13,}")
    with open("jummal_par_sourate.csv", "w", newline="", encoding="utf-8") as f:
        w = csv.writer(f); w.writerow(["sourate", "versets", "lettres", "jummal"])
        for s in sorted(agg):
            j, v, l = agg[s]; w.writerow([s, v, l, j])
    print(f"\n-> ecrit jummal_par_sourate.csv  ({len(agg)} sourates)")

_TABLE_GZ = ""

if __name__ == "__main__":
    main()
